import { useLocation, useNavigate } from "react-router-dom";
import { useState, useEffect } from "react";
import api from "../../api/axios";

export default function CustomerBookAppointment() {
  const { state } = useLocation();
  const navigate = useNavigate();

  const [vehicleId, setVehicleId] = useState("");
  const [vehicles, setVehicles] = useState([]);

  const [date, setDate] = useState("");
  const [time, setTime] = useState("");

  // Load available vehicles for dropdown
  useEffect(() => {
    const loadVehicles = async () => {
      try {
        const res = await api.get("/vehicles");
        const available = res.data.filter((v) => v.status === "available");
        setVehicles(available);

        // If coming from vehicle card, auto-select it
        if (state?.vehicleId) {
          setVehicleId(state.vehicleId);
        } else if (available.length > 0) {
          // If coming from navbar, default to first available vehicle
          setVehicleId(available[0]._id);
        }
      } catch (err) {
        alert(err.response?.data?.message || "Failed to load vehicles");
      }
    };

    loadVehicles();
  }, [state]);

  const submit = async (e) => {
    e.preventDefault();

    if (!vehicleId) {
      alert("Please select a vehicle");
      return;
    }

    try {
      await api.post("/customer/appointments/book", {
        vehicle: vehicleId,
        date,
        time,
      });

      alert("Appointment booked successfully!");
      navigate("/my-appointments");
    } catch (err) {
      alert(err.response?.data?.message || "Booking failed");
    }
  };

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">Book an Appointment</div>
          <div className="pageSub">Schedule a test drive or viewing</div>
        </div>
      </div>

      <div className="card cardPad" style={{ maxWidth: 560, margin: "32px auto" }}>
        <form onSubmit={submit}>
          <label className="label">Select Vehicle</label>
          <select
            value={vehicleId}
            onChange={(e) => setVehicleId(e.target.value)}
            className="select"
            required
          >
            {vehicles.length === 0 ? (
              <option value="">No available vehicles</option>
            ) : (
              vehicles.map((v) => (
                <option key={v._id} value={v._id}>
                  {v.brand} {v.model || v.type || ""} ({v.year})
                </option>
              ))
            )}
          </select>

          <label className="label" style={{ marginTop: 20 }}>Appointment Date</label>
          <input
            type="date"
            required
            value={date}
            onChange={(e) => setDate(e.target.value)}
            className="input"
          />

          <label className="label" style={{ marginTop: 20 }}>Preferred Time</label>
          <input
            type="time"
            required
            value={time}
            onChange={(e) => setTime(e.target.value)}
            className="input"
          />

          <div style={{ marginTop: 28, display: "flex", gap: 12 }}>
            <button
              type="submit"
              disabled={vehicles.length === 0}
              className="btn btnPrimary"
            >
              Book Appointment
            </button>
            <button
              type="button"
              onClick={() => navigate("/")}
              className="btn"
            >
              Cancel
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
